member.example:
Bind the CapsuleCollider center property using a serialized binder field — the target CapsuleCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CapsuleColliderCenterBinder _center;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _center;
    }


Bind the CapsuleCollider center property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CapsuleCollider _capsuleCollider;
        
        private CapsuleColliderCenterBinder Center =>
            new(_capsuleCollider);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _center;
    }

Switch the CapsuleCollider center between two Vector3 values using a serialized binder field — the target CapsuleCollider is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private CapsuleColliderCenterSwitcherBinder _isActive;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }


Switch the CapsuleCollider center between two Vector3 values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private CapsuleCollider _capsuleCollider;
        
        private CapsuleColliderCenterSwitcherBinder IsActive => new(
            _capsuleCollider,
            trueValue: new Vector3(0, 1, 0),
            falseValue: Vector3.zero);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isActive;
    }
